const messageText = $input.first().json.message.text;
const chatId = $input.first().json.message.chat.id;
const userId = $input.first().json.message.from.id;

// Extract URL from "/learn <url>"
const parts = messageText.split(/\s+/);
parts.shift(); // remove /learn
const url = parts.join(' ').trim();

if (!url || !url.startsWith('http')) {
  return [{ json: { error: true, chatId, userId, message: 'Please provide a valid URL. Usage: /learn https://example.com/article' } }];
}

return [{ json: { error: false, url, chatId, userId } }];

const url = $json.url;
const chatId = $json.chatId;
const userId = $json.userId;

try {
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: url,
    timeout: 10000,
    returnFullResponse: true,
    encoding: 'utf-8'
  });

  // Return the response body for downstream processing
  return [{ json: { data: typeof response === 'string' ? response : (response.body || ''), error: false, url, chatId, userId } }];
} catch (error) {
  // On fetch error, send Telegram message directly and stop the chain
  return [{ json: { error: true, chatId, userId, message: 'Could not fetch content from that URL. Please check the link and try again.' } }];
}

const html = $input.first().json.data || $input.first().json.body || '';
const url = $input.first().json.url || $('Extract URL').first().json.url;
const chatId = $('Extract URL').first().json.chatId;
const userId = $('Extract URL').first().json.userId;

// Strip HTML tags and clean up
let text = html
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/\s+/g, ' ')
  .trim();

// Truncate to ~4000 chars to stay within AI token limits
if (text.length > 4000) {
  text = text.substring(0, 4000) + '...';
}

// Extract title from HTML
const titleMatch = html.match(/<title[^>]*>(.*?)<\/title>/i);
const title = titleMatch ? titleMatch[1].trim() : 'Untitled';

// Generate material ID
const materialId = 'LM-' + Date.now();

return [{
  json: {
    materialId,
    url,
    title,
    content: text,
    chatId,
    userId,
    addedDate: new Date().toISOString()
  }
}];

const aiResponse = $input.first().json.text || $input.first().json.output || $input.first().json.message?.content || '';
const prevData = $('Clean HTML').first().json;

let parsed;
try {
  // Try to extract JSON from response
  const jsonMatch = aiResponse.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(jsonMatch ? jsonMatch[0] : aiResponse);
} catch (e) {
  parsed = {
    title: prevData.title,
    difficulty: 'unknown',
    summary: aiResponse.substring(0, 200),
    keyPoints: [aiResponse.substring(0, 100)],
    mainConcepts: []
  };
}

// Format Telegram message
const keyPointsText = parsed.keyPoints
  .map((p, i) => (i + 1) + '. ' + p)
  .join('\n');

const conceptsText = parsed.mainConcepts.join(', ');

const telegramMessage = '📚 *' + parsed.title + '*\n\n' +
  '📊 Difficulty: ' + parsed.difficulty + '\n\n' +
  '📝 Summary:\n' + parsed.summary + '\n\n' +
  '🔑 Key Points:\n' + keyPointsText + '\n\n' +
  '💡 Main Concepts: ' + conceptsText + '\n\n' +
  '_Use /quiz to test your knowledge!_';

// Data to store
const materialData = {
  id: prevData.materialId,
  url: prevData.url,
  title: parsed.title || prevData.title,
  content: prevData.content,
  summary: parsed.summary,
  keyPoints: parsed.keyPoints,
  mainConcepts: parsed.mainConcepts,
  difficulty: parsed.difficulty,
  addedDate: prevData.addedDate,
  userId: prevData.userId,
  chatId: prevData.chatId
};

return [{
  json: {
    telegramMessage,
    materialData,
    chatId: prevData.chatId
  }
}];

const material = $input.first().json.materialData;

const staticData = $getWorkflowStaticData('global');
if (!staticData.materials) {
  staticData.materials = {};
}
if (!staticData.userMaterials) {
  staticData.userMaterials = {};
}

staticData.materials[material.id] = material;

const userId = String(material.userId);
if (!staticData.userMaterials[userId]) {
  staticData.userMaterials[userId] = [];
}
staticData.userMaterials[userId].push(material.id);

return [$input.first()];

const chatId = $input.first().json.message.chat.id;
const userId = String($input.first().json.message.from.id);

const staticData = $getWorkflowStaticData('global');
const userMaterialIds = (staticData.userMaterials || {})[userId] || [];

if (userMaterialIds.length === 0) {
  return [{
    json: {
      hasTopics: false,
      chatId,
      userId,
      message: "You haven't saved any learning materials yet. Use /learn [URL] to add some first!"
    }
  }];
}

const topics = userMaterialIds.map(id => {
  const m = staticData.materials[id];
  return { id: m.id, title: m.title, difficulty: m.difficulty };
});

return [{
  json: {
    hasTopics: true,
    chatId,
    userId,
    topics
  }
}];

const { chatId, topics } = $input.first().json;

const inlineKeyboard = topics.map(t => [{
  text: '📚 ' + t.title + ' (' + t.difficulty + ')',
  callback_data: 'quiz_' + t.id
}]);

return [{
  json: {
    chatId,
    text: '📋 Select a topic to quiz on:',
    replyMarkup: JSON.stringify({
      inline_keyboard: inlineKeyboard
    })
  }
}];

const callback = $input.first().json.callback_query;
const chatId = callback.message.chat.id;
const userId = String(callback.from.id);
const data = callback.data;
const callbackId = callback.id;

let type = 'unknown';
let materialId = '';
let answer = '';

if (data.startsWith('quiz_')) {
  type = 'quiz_start';
  materialId = data.replace('quiz_', '');
} else if (data.startsWith('ans_')) {
  type = 'quiz_answer';
  const parts = data.split('_');
  materialId = parts[1];
  const questionIndex = parseInt(parts[2]);
  answer = parts[3];
  return [{ json: { type, chatId, userId, materialId, questionIndex, answer, callbackId } }];
}

return [{ json: { type, chatId, userId, materialId, callbackId } }];

const { materialId, chatId, userId, callbackId } = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const material = staticData.materials[materialId];

if (!material) {
  return [{ json: { error: true, chatId, message: 'Material not found.' } }];
}

return [{ json: { materialId, chatId, userId, callbackId, title: material.title, content: material.content, summary: material.summary, keyPoints: material.keyPoints } }];

const aiResponse = $input.first().json.message?.content || $input.first().json.text || $input.first().json.output || '';
const prevData = $('Load Material').first().json;

let quizData;
try {
  const jsonMatch = aiResponse.match(/\{[\s\S]*\}/);
  quizData = JSON.parse(jsonMatch ? jsonMatch[0] : aiResponse);
} catch (e) {
  return [{ json: { error: true, chatId: prevData.chatId, message: 'Failed to generate quiz. Please try again.' } }];
}

const staticData = $getWorkflowStaticData('global');
if (!staticData.activeQuizzes) staticData.activeQuizzes = {};

const userId = prevData.userId;
staticData.activeQuizzes[userId] = {
  materialId: prevData.materialId,
  questions: quizData.questions,
  answers: {},
  currentQuestion: 0
};

const q = quizData.questions[0];
const text = '📝 Quiz: *' + prevData.title + '*\n\nQuestion 1/5:\n' + q.question + '\n\nA) ' + q.options.A + '\nB) ' + q.options.B + '\nC) ' + q.options.C + '\nD) ' + q.options.D;

const inlineKeyboard = [[
  { text: 'A', callback_data: 'ans_' + prevData.materialId + '_0_A' },
  { text: 'B', callback_data: 'ans_' + prevData.materialId + '_0_B' },
  { text: 'C', callback_data: 'ans_' + prevData.materialId + '_0_C' },
  { text: 'D', callback_data: 'ans_' + prevData.materialId + '_0_D' }
]];

return [{ json: { chatId: prevData.chatId, text, replyMarkup: JSON.stringify({ inline_keyboard: inlineKeyboard }), error: false } }];

const { chatId, userId, materialId, questionIndex, answer, callbackId } = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const quiz = staticData.activeQuizzes[userId];

if (!quiz) {
  return [{ json: { chatId, action: 'error', message: 'No active quiz found. Use /quiz to start one.' } }];
}

quiz.answers[questionIndex] = answer;

const currentQ = quiz.questions[questionIndex];
const isCorrect = answer === currentQ.correctAnswer;
const nextIndex = questionIndex + 1;

if (nextIndex < quiz.questions.length) {
  const nextQ = quiz.questions[nextIndex];
  const text = (isCorrect ? '\u2705 Correct!' : '\u274C Incorrect. The answer was ' + currentQ.correctAnswer + '.') + '\n' + (!isCorrect ? currentQ.explanation + '\n' : '') + '\n' +
    'Question ' + (nextIndex + 1) + '/5:\n' + nextQ.question + '\n\n' +
    'A) ' + nextQ.options.A + '\nB) ' + nextQ.options.B + '\nC) ' + nextQ.options.C + '\nD) ' + nextQ.options.D;

  const inlineKeyboard = [
    [
      { text: 'A', callback_data: 'ans_' + materialId + '_' + nextIndex + '_A' },
      { text: 'B', callback_data: 'ans_' + materialId + '_' + nextIndex + '_B' },
      { text: 'C', callback_data: 'ans_' + materialId + '_' + nextIndex + '_C' },
      { text: 'D', callback_data: 'ans_' + materialId + '_' + nextIndex + '_D' }
    ]
  ];

  return [{
    json: {
      chatId,
      action: 'next_question',
      text,
      replyMarkup: JSON.stringify({ inline_keyboard: inlineKeyboard })
    }
  }];
} else {
  let correct = 0;
  let resultsText = '';

  for (let i = 0; i < quiz.questions.length; i++) {
    const q = quiz.questions[i];
    const userAns = quiz.answers[i];
    const wasCorrect = userAns === q.correctAnswer;
    if (wasCorrect) correct++;

    resultsText += (wasCorrect ? '\u2705' : '\u274C') + ' Q' + (i + 1) + ': ' + q.question + '\n';
    resultsText += 'Your answer: ' + userAns + ' | Correct: ' + q.correctAnswer + '\n';
    if (!wasCorrect) {
      resultsText += '\uD83D\uDCA1 ' + q.explanation + '\n';
    }
    resultsText += '\n';
  }

  resultsText = (isCorrect ? '\u2705 Correct!' : '\u274C Incorrect. The answer was ' + currentQ.correctAnswer + '.') + '\n' + (!isCorrect ? currentQ.explanation + '\n' : '') + '\n' +
    '\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n' +
    '\uD83D\uDCCA Quiz Results\n\n' +
    'Score: ' + correct + '/' + quiz.questions.length + ' (' + Math.round(correct / quiz.questions.length * 100) + '%)\n\n' +
    resultsText +
    'Use /quiz to try another topic!';

  delete staticData.activeQuizzes[userId];

  return [{
    json: {
      chatId,
      action: 'show_results',
      text: resultsText
    }
  }];
}

const { chatId, text, replyMarkup, action } = $input.first().json;
const body = { chat_id: chatId, text: text };
if (replyMarkup) {
  body.reply_markup = JSON.parse(replyMarkup);
}
return [{ json: body }];
